#include <iostream>
#include <string>
#include <sstream>

extern bool isValidTriangle(int a, int b, int c);

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        int a, b, c;
        if (ss >> a >> b >> c) {
            std::cout << (isValidTriangle(a, b, c) ? "true" : "false") << std::endl;
        } else {
            std::cout << "false" << std::endl;
        }
    }
    return 0;
}
